mapper.select:
SELECT id, user_id, access_token, refresh_token, token_type, expire_time,
       refresh_expire_time, version, status, create_time, update_time
FROM t_token WHERE access_token = #{accessToken}

SELECT id, user_id, access_token, refresh_token, token_type, expire_time,
       refresh_expire_time, version, status, create_time, update_time
FROM t_token WHERE refresh_token = #{refreshToken}

SELECT id, user_id, access_token, refresh_token, token_type, expire_time,
       refresh_expire_time, version, status, create_time, update_time
FROM t_token WHERE user_id = #{userId}
